    public static function rowsBySlug(): array
    {
        $grouped = [];
        foreach (self::rows() as $row) {
            $slug = (string)($row['slug'] ?? '');
            if ($slug === '') {
                continue;
            }
            $grouped[$slug][] = $row;
        }
        return $grouped;
    }
}